    // MARK: - Password Status & UI Updates

    /// Checks if a password has already been set and updates the UI accordingly.
    private func checkPasswordStatus() {
        if keychainService.itemExists(key: passwordHashKey) && keychainService.itemExists(key: passwordSaltKey) {
            messageLabel.text = "Status: Password already set. Ready to verify."
            setPasswordButton.isEnabled = false
            setPasswordButton.alpha = 0.5
            verifyPasswordButton.isEnabled = true
            verifyPasswordButton.alpha = 1.0
            deletePasswordButton.isEnabled = true
            deletePasswordButton.alpha = 1.0
        } else {
            messageLabel.text = "Status: No password set. Please set one."
            setPasswordButton.isEnabled = true
