            // 1. Load the stored salt and hash from Keychain
            let storedSalt = try keychainService.load(key: passwordSaltKey)
            let storedHash = try keychainService.load(key: passwordHashKey)

            // 2. Verify the entered password against the stored credentials
            if passwordHashingService.verify(password: password, storedSalt: storedSalt, storedHash: storedHash) {
                messageLabel.text = "Status: Password verified successfully! (Offline)"
